import React, { useState, useCallback } from 'react';
import BackButton from '../components/BackButton';

type Strength = 'low' | 'medium' | 'high';

const PasswordGenerator: React.FC = () => {
  const [length, setLength] = useState<number>(16);
  const [strength, setStrength] = useState<Strength>('medium');
  const [passwords, setPasswords] = useState<string[]>([]);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);

  const generatePasswords = useCallback(() => {
    const charSets = {
      lowercase: 'abcdefghijklmnopqrstuvwxyz',
      uppercase: 'ABCDEFGHIJKLMNOPQRSTUVWXYZ',
      numbers: '0123456789',
      symbols: '!@#$%^&*()_+-=[]{}|;:,.<>?',
    };

    let chars = '';
    switch (strength) {
      case 'low':
        chars = charSets.lowercase + charSets.numbers;
        break;
      case 'medium':
        chars = charSets.lowercase + charSets.uppercase + charSets.numbers;
        break;
      case 'high':
        chars = charSets.lowercase + charSets.uppercase + charSets.numbers + charSets.symbols;
        break;
    }

    const newPasswords: string[] = [];
    for (let i = 0; i < 10; i++) {
      let password = '';
      for (let j = 0; j < length; j++) {
        password += chars.charAt(Math.floor(Math.random() * chars.length));
      }
      newPasswords.push(password);
    }
    setPasswords(newPasswords);
    setCopiedIndex(null);
  }, [length, strength]);

  const handleCopy = (password: string, index: number) => {
    navigator.clipboard.writeText(password);
    setCopiedIndex(index);
    setTimeout(() => setCopiedIndex(null), 2000);
  };

  return (
    <div className="container mx-auto px-4 py-12">
      <BackButton />
      <h1 className="text-4xl font-bold mb-8 text-white">Random Password Generator</h1>

      <div className="bg-gray-800 p-8 rounded-lg shadow-lg grid grid-cols-1 md:grid-cols-3 gap-8">
        {/* Controls */}
        <div className="md:col-span-1 space-y-6">
          <div>
            <label htmlFor="length" className="block text-sm font-medium text-gray-300 mb-2">Password Length: <span className="font-bold text-primary">{length}</span></label>
            <input
              id="length"
              type="range"
              min="8"
              max="64"
              value={length}
              onChange={(e) => setLength(parseInt(e.target.value, 10))}
              className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-primary"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">Strength</label>
            <div className="flex space-x-2">
              {(['low', 'medium', 'high'] as Strength[]).map(s => (
                <button
                  key={s}
                  onClick={() => setStrength(s)}
                  className={`capitalize w-full py-2 px-4 rounded-md transition-colors text-sm font-semibold ${strength === s ? 'bg-primary text-white' : 'bg-gray-700 hover:bg-gray-600'}`}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>

          <button
            onClick={generatePasswords}
            className="w-full bg-primary text-white font-bold py-3 px-4 rounded-lg hover:bg-primary-hover transition-colors duration-300"
          >
            Generate
          </button>
        </div>

        {/* Results */}
        <div className="md:col-span-2 bg-gray-900 p-6 rounded-lg">
          <h2 className="text-xl font-semibold mb-4 text-gray-200">Generated Passwords</h2>
          {passwords.length > 0 ? (
            <div className="space-y-3">
              {passwords.map((p, i) => (
                <div key={i} className="flex items-center justify-between bg-gray-800 p-3 rounded-md">
                  <span className="font-mono text-gray-300 break-all">{p}</span>
                  <button onClick={() => handleCopy(p, i)} className="text-sm font-semibold text-primary hover:underline ml-4 whitespace-nowrap">
                    {copiedIndex === i ? 'Copied!' : 'Copy'}
                  </button>
                </div>
              ))}
            </div>
          ) : (
            <p className="text-gray-500 text-center py-10">Click "Generate" to create new passwords.</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default PasswordGenerator;

import React, { useState, useRef, useEffect } from 'react';
import BackButton from '../components/BackButton';

interface Filters {
  brightness: number;
  contrast: number;
  saturate: number;
  grayscale: number;
  sepia: number;
  hueRotate: number;
}

const ImageEditor: React.FC = () => {
  const [imageSrc, setImageSrc] = useState<string | null>(null);
  const [filters, setFilters] = useState<Filters>({
    brightness: 100,
    contrast: 100,
    saturate: 100,
    grayscale: 0,
    sepia: 0,
    hueRotate: 0,
  });
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const imageRef = useRef<HTMLImageElement | null>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const img = new Image();
        img.onload = () => {
            imageRef.current = img;
            setImageSrc(event.target?.result as string);
        };
        img.src = event.target?.result as string;
      };
      reader.readAsDataURL(e.target.files[0]);
    }
  };

  useEffect(() => {
    if (imageRef.current && canvasRef.current && imageSrc) {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        canvas.width = imageRef.current.width;
        canvas.height = imageRef.current.height;

        ctx.filter = `
          brightness(${filters.brightness}%)
          contrast(${filters.contrast}%)
          saturate(${filters.saturate}%)
          grayscale(${filters.grayscale}%)
          sepia(${filters.sepia}%)
          hue-rotate(${filters.hueRotate}deg)
        `;
        ctx.drawImage(imageRef.current, 0, 0);
      }
    }
  }, [imageSrc, filters]);

  const handleFilterChange = (filterName: keyof Filters, value: number) => {
    setFilters(prev => ({ ...prev, [filterName]: value }));
  };

  const resetFilters = () => {
    setFilters({ brightness: 100, contrast: 100, saturate: 100, grayscale: 0, sepia: 0, hueRotate: 0 });
  };

  const downloadImage = () => {
    if (canvasRef.current) {
      const link = document.createElement('a');
      link.download = 'edited-image.png';
      link.href = canvasRef.current.toDataURL('image/png');
      link.click();
    }
  };

  return (
    <div className="container mx-auto px-4 py-12">
      <BackButton />
      <h1 className="text-4xl font-bold mb-8 text-white">Instant Image Editor</h1>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-gray-800 p-4 rounded-lg flex items-center justify-center min-h-[60vh]">
          {imageSrc ? (
            <canvas ref={canvasRef} className="max-w-full max-h-[80vh] object-contain rounded-md" />
          ) : (
            <div className="text-center text-gray-500">
              <p className="mb-4">Upload an image to start editing</p>
              <label className="bg-primary text-white font-bold py-2 px-4 rounded-lg hover:bg-primary-hover transition-colors duration-300 cursor-pointer">
                Choose Image
                <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
              </label>
            </div>
          )}
        </div>

        <div className="lg:col-span-1 bg-gray-800 p-6 rounded-lg self-start">
          <h2 className="text-xl font-semibold mb-4">Controls</h2>
          {!imageSrc && <p className="text-gray-500 text-sm">Upload an image to enable controls.</p>}
          <div className={`space-y-4 ${!imageSrc ? 'opacity-50 pointer-events-none' : ''}`}>
            {Object.keys(filters).map((key) => {
              const filterKey = key as keyof Filters;
              const max = filterKey === 'hueRotate' ? 360 : 200;
              const min = 0;
              const value = filters[filterKey];
              return (
                 <div key={filterKey}>
                    <label className="block text-sm font-medium capitalize text-gray-300 mb-1">{filterKey.replace('Rotate', ' Rotate')}: {value}</label>
                    <input type="range" min={min} max={max} value={value} onChange={(e) => handleFilterChange(filterKey, parseInt(e.target.value))} className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-primary" />
                 </div>
              )
            })}
             <div className="flex space-x-2 pt-4">
              <button onClick={resetFilters} className="w-full bg-gray-600 text-white font-bold py-2 px-4 rounded-lg hover:bg-gray-500 transition-colors">Reset</button>
              <button onClick={downloadImage} className="w-full bg-primary text-white font-bold py-2 px-4 rounded-lg hover:bg-primary-hover transition-colors">Download</button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ImageEditor;

import React, { useState, useRef } from 'react';
import BackButton from '../components/BackButton';

const resolutions = [
  { name: '1080p (Full HD)', w: 1920, h: 1080 },
  { name: '720p (HD)', w: 1280, h: 720 },
  { name: '4K (UHD)', w: 3840, h: 2160 },
  { name: 'Square (1:1)', w: 1080, h: 1080 },
  { name: 'Portrait (4:5)', w: 1080, h: 1350 },
];

const ResolutionChanger: React.FC = () => {
  const [imageSrc, setImageSrc] = useState<string | null>(null);
  const [selectedRes, setSelectedRes] = useState<string>(resolutions[0].name);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const imageRef = useRef<HTMLImageElement | null>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const img = new Image();
        img.onload = () => {
          imageRef.current = img;
          setImageSrc(event.target?.result as string);
        };
        img.src = event.target?.result as string;
      };
      reader.readAsDataURL(e.target.files[0]);
    }
  };

  const handleDownload = () => {
    if (!imageRef.current) return;
    setIsProcessing(true);

    const targetRes = resolutions.find(r => r.name === selectedRes);
    if (!targetRes) {
        setIsProcessing(false);
        return;
    }

    const canvas = document.createElement('canvas');
    canvas.width = targetRes.w;
    canvas.height = targetRes.h;
    const ctx = canvas.getContext('2d');

    if (ctx) {
        ctx.drawImage(imageRef.current, 0, 0, targetRes.w, targetRes.h);
        const link = document.createElement('a');
        link.download = `resized-${targetRes.w}x${targetRes.h}.png`;
        link.href = canvas.toDataURL('image/png');
        link.click();
    }

    setIsProcessing(false);
  };

  return (
    <div className="container mx-auto px-4 py-12">
      <BackButton />
      <h1 className="text-4xl font-bold mb-8 text-white">Image Resolution Changer</h1>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-gray-800 p-4 rounded-lg flex items-center justify-center min-h-[50vh]">
          {imageSrc ? (
            <img src={imageSrc} alt="Preview" className="max-w-full max-h-[70vh] object-contain rounded-md" />
          ) : (
            <div className="text-center text-gray-500">
              <label className="bg-primary text-white font-bold py-3 px-6 rounded-lg hover:bg-primary-hover transition-colors duration-300 cursor-pointer">
                Choose Image
                <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
              </label>
            </div>
          )}
        </div>

        <div className="lg:col-span-1 bg-gray-800 p-6 rounded-lg self-start">
          <h2 className="text-xl font-semibold mb-4">Options</h2>
          <div className={`space-y-4 ${!imageSrc ? 'opacity-50 pointer-events-none' : ''}`}>
            <div>
              <label htmlFor="resolution" className="block text-sm font-medium text-gray-300 mb-2">Target Resolution</label>
              <select
                id="resolution"
                value={selectedRes}
                onChange={(e) => setSelectedRes(e.target.value)}
                className="w-full bg-gray-700 text-white p-3 rounded-md border border-gray-600 focus:ring-primary focus:border-primary"
              >
                {resolutions.map(r => (
                  <option key={r.name} value={r.name}>{r.name} - {r.w}x{r.h}</option>
                ))}
              </select>
            </div>
            <button
              onClick={handleDownload}
              disabled={isProcessing}
              className="w-full bg-primary text-white font-bold py-3 px-4 rounded-lg hover:bg-primary-hover transition-colors disabled:bg-gray-500 disabled:cursor-not-allowed"
            >
              {isProcessing ? 'Processing...' : 'Change & Download'}
            </button>
          </div>
          {!imageSrc && <p className="text-gray-500 text-sm mt-4">Upload an image to get started.</p>}
        </div>
      </div>
    </div>
  );
};

export default ResolutionChanger;

import React, { useState, useMemo } from 'react';
import BackButton from '../components/BackButton';

const TextCounter: React.FC = () => {
  const [text, setText] = useState<string>('');

  const stats = useMemo(() => {
    const trimmedText = text.trim();

    const characters = text.length;
    const words = trimmedText ? trimmedText.split(/\s+/).filter(Boolean).length : 0;
    const sentences = trimmedText ? (trimmedText.match(/[.!?]+(?=\s|$)/g) || []).length + (trimmedText.endsWith('.') || trimmedText.endsWith('!') || trimmedText.endsWith('?') ? 0 : (trimmedText ? 1 : 0)) - (trimmedText.match(/[.!?]+(?=\s|$)/g)?.length === 0 && !trimmedText ? 1 : 0) : 0;
    const paragraphs = trimmedText ? trimmedText.split(/\n+/).filter(p => p.trim().length > 0).length : 0;

    // Ensure sentences is not negative for single non-ending-punctuation word
    const finalSentences = (words > 0 && sentences === 0) ? 1 : sentences;


    return { characters, words, sentences: finalSentences, paragraphs };
  }, [text]);

  const StatBox: React.FC<{ title: string; value: number }> = ({ title, value }) => (
    <div className="bg-gray-900 p-4 rounded-lg text-center">
        <p className="text-sm text-gray-400">{title}</p>
        <p className="text-3xl font-bold text-primary">{value}</p>
    </div>
  );

  return (
    <div className="container mx-auto px-4 py-12">
      <BackButton />
      <h1 className="text-4xl font-bold mb-2 text-white">Word & Character Counter</h1>
      <p className="text-gray-400 mb-8">Get instant text analysis as you type.</p>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
        <StatBox title="Words" value={stats.words} />
        <StatBox title="Characters" value={stats.characters} />
        <StatBox title="Sentences" value={stats.sentences} />
        <StatBox title="Paragraphs" value={stats.paragraphs} />
      </div>

      <div className="bg-gray-800 p-2 rounded-lg shadow-lg">
        <textarea
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="Start typing or paste your text here..."
          className="w-full h-96 bg-gray-800 text-gray-200 p-4 rounded-md border-none focus:ring-2 focus:ring-primary resize-none"
        />
      </div>
    </div>
  );
};

export default TextCounter;

