                    </label>
                    <label class="inline-flex items-center">
                        <input type="radio" name="complexity" value="high" class="form-radio text-yellow-500">
                        <span class="ml-2 text-gray-300">High</span>
                    </label>
                </div>
            </div>
        </div>

        <!-- Generate button -->
        <button id="generate-btn"
                class="w-full bg-yellow-500 text-gray-900 font-bold py-3 px-6 rounded-lg
                shadow-md hover:bg-yellow-600 transition-colors duration-300 transform
                hover:scale-105 focus:outline-none focus:ring-2 focus:ring-yellow-500 focus:ring-opacity-50">
            Generate 10 Passwords
        </button>

        <!-- Password list section -->
        <div id="password-list" class="mt-8 space-y-4">
            <!-- Passwords will be dynamically added here -->
        </div>

    </div>

    <script>
        // Get references to DOM elements
        const generateBtn = document.getElementById('generate-btn');
        const charLimitInput = document.getElementById('char-limit');
        const passwordList = document.getElementById('password-list');

        // Define character sets for password generation
        const charSets = {
            low: 'abcdefghijklmnopqrstuvwxyz',
            medium: 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz',
            high: 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!@#$%^&*()_+'
        };

        /**
         * Generates a single password based on length and complexity.
         * @param {number} length The desired length of the password.
         * @param {string} complexity The complexity level ('low', 'medium', 'high').
         * @returns {string} The generated password.
         */
        function generatePassword(length, complexity) {
            const chars = charSets[complexity];
            let password = '';
            for (let i = 0; i < length; i++) {
                password += chars.charAt(Math.floor(Math.random() * chars.length));
            }
            return password;
        }

        /**
         * Handles the click event for the generate button.
         * Clears the current list and generates 10 new passwords.
         */
        generateBtn.addEventListener('click', () => {
            const length = parseInt(charLimitInput.value, 10);
            const complexity = document.querySelector('input[name="complexity"]:checked').value;

            // Clear previous passwords
            passwordList.innerHTML = '';

            // Generate and display 10 passwords
            for (let i = 0; i < 10; i++) {
                const password = generatePassword(length, complexity);
                createPasswordItem(password);
            }
        });

        /**
         * Creates and appends a new password item to the list.
         * @param {string} password The password to display.
         */
        function createPasswordItem(password) {
            const passwordItem = document.createElement('div');
            passwordItem.className = 'flex items-center bg-gray-700 rounded-lg p-3 shadow-md';

            // Display the password
            const passwordText = document.createElement('span');
            passwordText.textContent = password;
            passwordText.className = 'flex-grow text-yellow-300 font-mono break-all';

            // Create the copy button
            const copyBtn = document.createElement('button');
            copyBtn.textContent = 'Copy';
            copyBtn.className = 'ml-4 bg-gray-500 text-gray-900 font-bold text-sm py-1 px-3 rounded-lg hover:bg-gray-400 transition-colors duration-300';

            // Add copy functionality
            copyBtn.addEventListener('click', () => {
                const tempInput = document.createElement('textarea');
                tempInput.value = password;
                document.body.appendChild(tempInput);
                tempInput.select();
                document.execCommand('copy');
                document.body.removeChild(tempInput);
                copyBtn.textContent = 'Copied!';
                copyBtn.disabled = true;
                setTimeout(() => {
                    copyBtn.textContent = 'Copy';
                    copyBtn.disabled = false;
                }, 2000);
            });

            passwordItem.appendChild(passwordText);
            passwordItem.appendChild(copyBtn);
            passwordList.appendChild(passwordItem);
        }

        // Generate initial passwords on page load
        document.addEventListener('DOMContentLoaded', () => {
            generateBtn.click();
        });

    </script>
</body>
