// Helper function  for compression logic
async function compressImage(
  image: HTMLImageElement,
  targetSizeKB: number
 ): Promise<Blob> {
  const targetSizeBytes = targetSizeKB * 1024;
  const canvas  = document.createElement('canvas');
  canvas.width = image.naturalWidth;
  canvas.height =  image.naturalHeight;
  const ctx = canvas.getContext('2d');
  if (!ctx) { 
    throw new Error('Could not get canvas context');
  }
  ctx.drawImage(image,  0, 0);

  // Initial check with max quality
  const maxQualityBlob = await new Promise<Blob  | null>(resolve => 
    canvas.toBlob(blob => resolve(blob), 'image/jpeg',  1.0)
  );

  if (!maxQualityBlob) {
    throw new Error('Could  not create blob');
  }

  // If even max quality is smaller than target, return it.
   if (maxQualityBlob.size <= targetSizeBytes) {
    return maxQualityBlob;
  }

   // Binary search for the best quality
  let minQuality = 0;
  let maxQuality = 1 ;
  let bestBlob: Blob = maxQualityBlob;

  for (let i = 0; i <  10; i++) { // 10 iterations are enough for precision
    const quality = (minQuality  + maxQuality) / 2;
    const currentBlob = await new Promise<Blob | null>(resolve =>  
      canvas.toBlob(blob => resolve(blob), 'image/jpeg', quality)
    ); 

    if (!currentBlob) continue;

    if (currentBlob.size > targetSizeBytes) {
      maxQuality  = quality;
    } else {
      bestBlob = currentBlob; // It's a candidate
      minQuality =  quality;
    }
  }

  return bestBlob;
}
